-- Seed the comment bank from the Lead-approved master workbook.
-- Source: ACFM_Comment_Bank_MASTER.xlsx (one sheet per subject).
-- Generated by scripts/build_master_seed.cjs — DO NOT hand-edit; regenerate.
--
-- This REPLACES the two earlier seed banks
-- (20260508000001_seed_comment_bank_sem1_sem2.sql,
--  20260509000001_seed_comment_bank_sem3_sem6.sql) with the refined wording.
--
-- 1211 comments across 7 subjects, Sem I-VI, grades A-D.
--
-- Replace strategy: delete existing comments that no saved grade references
-- (every comment on a pre-launch DB), then insert the master set. Comments
-- still referenced by a student_grades row are left untouched so the FK
-- (student_grades.comment_id ON DELETE RESTRICT) can't block this migration.

DELETE FROM public.comment_bank cb
WHERE NOT EXISTS (
  SELECT 1 FROM public.student_grades sg WHERE sg.comment_id = cb.id
);

INSERT INTO public.comment_bank (semester, subject_id, grade, body)
SELECT v.semester, s.id, v.grade, v.body
FROM (VALUES
  (1, 'direction', 'A', 'Demonstrates strong analytical ability in interpreting films, with clear understanding of directorial intent, visual language, and narrative construction. Keep it up and keep watching films immersively as a filmmaker.'),
  (1, 'direction', 'A', 'Applies visual storytelling techniques such as composition, camera angles, and continuity with clarity and purpose. A fine foundation to now stretch into bolder, more expressive choices.'),
  (1, 'direction', 'A', 'Effectively translates real-world observations into structured visual narratives with originality and insight. Continue building on this strength by testing more ambitious and relavent narrative structures.'),
  (1, 'direction', 'A', 'Demonstrates a strong understanding of continuity and visual planning, ensuring clarity in scene progression and cinematic connection. A solid base from which to attempt more complex, multi-location sequences.'),
  (1, 'direction', 'A', 'Maintains a detailed and reflective film diary, demonstrating critical thinking and an evolving directorial perspective. Keep deepening this habit, as it is where a personal voice takes shape.'),
  (1, 'direction', 'A', 'Actively engages in collaborative exercises, contributing effectively to camera, edit, and sound integration. A real strength to carry into leading larger crews.'),
  (1, 'direction', 'A', 'Demonstrates strong awareness of time and space in filmmaking, constructing scenes with logical progression. We encourage you to now experiment with how rhythm and ellipsis can shape that progression further.'),
  (1, 'direction', 'A', 'Shows initiative in exploring different filmmaking approaches through case studies and practical exercises. Continue this curiosity, letting it sharpen into a distinct personal interpretation.'),
  (1, 'direction', 'B', 'Shows a good understanding of film analysis, with readings that are currently more descriptive than critical. Advice to develop sharper insight by asking why a choice was made and what it achieves emotionally — critical depth grows through repeated viewing and close analysis.'),
  (1, 'direction', 'B', 'Demonstrates working knowledge of visual storytelling techniques. Advice to develop greater consistency in execution by planning each shot''s purpose in advance — reliable craft comes through repeated practice and review of your own work.'),
  (1, 'direction', 'B', 'Engages well with observational exercises. To turn observation into compelling visual narrative, advice to practice selecting the single most telling detail and building a clear point of view around it — this skill strengthens with repeated fieldwork and feedback.'),
  (1, 'direction', 'B', 'Understands the basics of continuity and decoupage. Advice to develop clarity in complex scenes by breaking them down into a shot-by-shot plan that tracks eyelines and screen direction — confidence here comes through repeated, deliberate practice. Keep it up!'),
  (1, 'direction', 'B', 'Maintains a film diary, a habit worth deepening. Advice to develop more consistent and reflective entries by noting not just what was filmed but why each choice was made — this reflection is what sharpens a directorial perspective over time.'),
  (1, 'direction', 'B', 'Participates well in collaborative exercises. Advice to contribute more proactively, voice creative ideas early and take ownership of a clear role — teamwork and leadership in a crew develops through repeated ownership, practice and feedback.'),
  (1, 'direction', 'B', 'Shows clear awareness of time and space in scenes. Advice to develop greater precision in execution by rehearsing blocking and timing before the shoot — accuracy of this kind comes through repeated practice, planing and careful review.'),
  (1, 'direction', 'B', 'Demonstrates familiarity with different filmmaking approaches. Advice to develop a stronger personal interpretation by choosing one approach and committing to it fully in an exercise — a distinct voice emerges through repeated experimentation.'),
  (1, 'direction', 'C', 'Currently engages with film analysis at a surface level. Advice to develop deeper readings by examining how specific directorial choices create meaning, supporting each point with a concrete example from the film — critical depth grows through repeated and immersive viewing of films, along with guided analysis.'),
  (1, 'direction', 'C', 'Developing consistency in applying visual storytelling principles. Advice to practice clearer visual communication by deciding the intention for each shot, exactly what the audience should feel and how framing delivers it — clarity comes through repeated practice and feedback.'),
  (1, 'direction', 'C', 'Developing a more structured framework for observational exercises. Advice to develop clarity by defining a single clear idea per exercise and arranging your shots so each builds on the last — structured visual narrative is a skill that strengthens with repeated practice.'),
  (1, 'direction', 'C', 'Continuity is still developing and scenes vary in consistency. Advice to practice maintaining screen direction and matching action across cuts by storyboarding before shooting — consistency here is built through repeated, deliberate practice.'),
  (1, 'direction', 'C', 'Develop a more consistent routine for film diary entries. Advice to build a reflection habit by writing a short entry after every exercise that records one thing learned and one to try next — critical engagement deepens through this steady practice.'),
  (1, 'direction', 'C', 'Currently a quieter presence in collaborative exercises. Advice to maximise participation by taking on one clear responsibility each session and sharing ideas openly — making a film requires teamwork and collaborative skill, confidence grows through repeated, active involvement.'),
  (1, 'direction', 'C', 'Understanding of spatial and temporal relationships is still developing. Advice to practice by mapping each scene''s geography and timeline before shooting, so the audience always knows where and when they are — this comes through repeated practice and feedback.'),
  (1, 'direction', 'C', 'Currently exploring a narrow range of filmmaking approaches. Advice to actively try different methods in practical exercises, reflecting on what each one offers — a versatile, confident style develops through repeated experimentation.'),
  (1, 'direction', 'D', 'Engagement with film analysis is currently limited. Advice to begin by watching one scene repeatedly and noting each visible directorial choice, then asking what it adds — understanding of cinematic language is built gradually through this kind of repeated, immersive, supported practice.'),
  (1, 'direction', 'D', 'Fundamental visual storytelling principles such as composition and continuity are still emerging. Advice to practice one principle at a time, for example holding consistent framing across a short exercise — these foundations grow steadily through repeated practice and feedback.'),
  (1, 'direction', 'D', 'Observational exercises are currently approached at a basic level. Advice to engage more meaningfully by spending real time watching a subject and recording specific details, then shaping them into a simple story — narrative interpretation develops through repeated, patient practice, working with actors and understanding their process.'),
  (1, 'direction', 'D', 'Continuity and decoupage need foundational development. Advice to start with very short two- or three-shot exercises, checking that action and eyelines match across each cut — coherent scene construction is built step by step through repeated practice and feedback.'),
  (1, 'direction', 'D', 'Film diary currently falls short of academic requirements. Advice to write regularly, even briefly, after each session, recording the film viewed, discussed and what was seen, learned — consistency, observation and reflective depth build gradually with this steady habit.'),
  (1, 'direction', 'D', 'Participation in collaborative exercises is currently limited. Advice to actively take a clear role in each group task and build from there — both learning and contribution strengthen through repeated, active involvement, ownership and contribution within group.'),
  (1, 'direction', 'D', 'Understanding of time and space in filmmaking is still at an early stage. Advice to practice with simple exercises that establish a clear location and order of events and impact required for each scene before adding complexity — this foundation develops through repeated, guided practice.'),
  (1, 'direction', 'D', 'Engagement with course content and practical exercises is currently low. Advice to set one small, achievable goal for each session and complete it — initiative and confidence grow steadily through repeated small successes and regular feedback. Only you can engage with your course.'),
  (2, 'direction', 'A', 'Demonstrates strong control over staging and blocking, using space, movement, and composition with clear narrative intention. A real strength to now extend into longer, more intricate sequences. Keep it up.'),
  (2, 'direction', 'A', 'Works effectively with actors, guiding performances with clarity, consistency, and sensitivity to character needs. Continue building on this by exploring more layered emotional beats, mannerisms and moods. Well done.'),
  (2, 'direction', 'A', 'Shows a nuanced understanding of scene construction, integrating performance, blocking, and visual elements cohesively. A strong base from which to attempt more complex and ambitious scenes. Keep up the good work.'),
  (2, 'direction', 'A', 'Applies staging patterns (I, A, L, C, S) effectively to support visual storytelling and spatial dynamics. We encourage you to keep stretching these into suitable, dynamic, motivated movement.'),
  (2, 'direction', 'A', 'Demonstrates strong command over visualisation tools, including storyboards and mood boards, to clearly communicate directorial intent. A valuable skill to carry into larger productions, for improving production value and aesthetics. Well done.'),
  (2, 'direction', 'A', 'Shows clarity in using props and space meaningfully to support narrative and character behaviour. Continue refining this instinct toward even more precise, layered detail that supports aesthetics and production value.'),
  (2, 'direction', 'A', 'Demonstrates control over rhythm and pacing, shaping scenes effectively through performance and visual flow. A fine foundation to now experiment with bolder tonal shifts. Keep it up.'),
  (2, 'direction', 'A', 'Shows maturity in handling complex staging situations, including working with VFX-based or virtual elements. A strong asset to develop further on larger-scale projects. Keep it up.'),
  (2, 'direction', 'B', 'Shows a good understanding of staging and blocking. Advice to develop consistency in more complex scenes by planning actor movement against the camera in advance — reliable control of complex blocking comes through repeated practice and feedback. All the best.'),
  (2, 'direction', 'B', 'Works effectively with actors in parts. Advice to develop continuity of performance across scenes by tracking each character''s emotional state from shot to shot — this is an important observation and awareness skill to build for Direction. Steady control of performance grows through repeated rehearsal and practice.'),
  (2, 'direction', 'B', 'Demonstrates a solid understanding of scene construction. Advice to refine coherence by ensuring blocking, performance, and visuals all serve one clear intention per scene — this integration sharpens through repeated practice and review.'),
  (2, 'direction', 'B', 'Uses staging patterns with some awareness. Advice to develop ability to choose a pattern deliberately for each scene and motivating it through the story — expertise comes through repeated practice, more precise and consistent application of staging patterns.'),
  (2, 'direction', 'B', 'Uses visualisation tools adequately. Advice to add greater clarity and depth by detailing framing, movement, and intent in each storyboard panel — strong pre-visualisation is a skill built through repeated, careful practice.'),
  (2, 'direction', 'B', 'Shows awareness of rhythm and pacing. Advice to develop consistency across scenes by planning the intended tempo of each beat in advance and checking it in the edit — steady pacing comes through repeated practice and feedback.'),
  (2, 'direction', 'B', 'Shows awareness of rhythm and pacing. Advice to develop more consistent control by mapping the rise and fall of each scene before shooting — maintaining rhythm reliably is a Filmmaking craft that strengthens through repeated practice.'),
  (2, 'direction', 'B', 'Engages well with advanced staging concepts. Advice to strengthen consistency in execution by breaking complex setups into clear, impactful and rehearsed steps — confident handling of advanced staging comes through repeated practice and feedback.'),
  (2, 'direction', 'C', 'Control over staging and blocking is still developing. Advice to practice creating clearer, motivated movement by giving each actor a reason to move tied to the story / setting — purposeful blocking strengthens through repeated, guided practice.'),
  (2, 'direction', 'C', 'Ability to direct actors is still developing. Advice to practice achieving consistent performances by giving simple, clear communication, action-based directions, and rehearsing before rolling — directing actors is a communication skill that grows through repeated practice and feedback.'),
  (2, 'direction', 'C', 'Scene construction shows developing cohesion. In order to improve, advice to integrate visual and performance elements by deciding the single feeling each scene should deliver, and aligning every choice to it — cohesion strengthens through repeated practice.'),
  (2, 'direction', 'C', 'Understanding of staging patterns is still developing. Advice to practice applying one pattern at a time in short exercises until it feels natural — confident use of staging patterns is built through repeated, deliberate practice.'),
  (2, 'direction', 'C', 'Visualisation tools are not yet used to full effect. Advice to practice clearer planning by sketching each key shot with notes on framing and movement before the shoot — strong pre-visualisation develops through repeated practice and feedback.'),
  (2, 'direction', 'C', 'Use of props and space shows developing intent. Advice to make choices more purposeful by asking what each prop and position reveals about the character or story — meaningful staging grows through repeated, deliberate practice.'),
  (2, 'direction', 'C', 'Rhythm and pacing show developing control. Advice to improve consistency and engagement by planning the tempo of each beat with intention and reviewing it in the edit — control of pacing is a Direction skill that strengthens with deliberate practice.'),
  (2, 'direction', 'C', 'Ability to handle complex staging, including VFX or spatial planning, is still developing. Advice to practice by breaking each complex setup into small, planned steps — confidence with VFX staging is built through repeated practice and feedback.'),
  (2, 'direction', 'D', 'Understanding of staging and blocking is at an early, emerging stage. Advice to begin with simple two-person scenes, planning where each actor stands and moves and why — effective scene construction is built step by step through repeated, guided practice.'),
  (2, 'direction', 'D', 'Ability to direct actors is just emerging. Advice to start by giving one clear, simple instruction per take and rehearsing it calmly — clearer- precise communication with actors enables more engaged performances. Directing actors is a craft that develops through repeated practice and encouragement.'),
  (2, 'direction', 'D', 'Scene construction is in early development. Advice to begin by ensuring each scene has one clear purpose and that visuals and performance both serve it — coherence is built gradually through repeated, supported practice.'),
  (2, 'direction', 'D', 'Understanding of staging patterns and spatial dynamics is just emerging. Advice to practice one simple pattern at a time in short exercises — confident spatial staging develops step by step through repeated practice. Keep practicing.'),
  (2, 'direction', 'D', 'Visualisation tools are not yet supporting the work effectively. Advice to begin by sketching even rough storyboards for each scene before shooting — clear scene planning grows steadily through this regular, repeated habit.'),
  (2, 'direction', 'D', 'Use of props and space shows emerging intent. Advice to start by choosing one prop per scene that means something to the character and placing it deliberately — purposeful staging is built gradually through repeated practice and feedback.'),
  (2, 'direction', 'D', 'Control over rhythm and pacing is just emerging. Advice to practice with short exercises where you decide in advance how fast or slow each moment should feel — consistent pacing develops step by step through repeated, guided practice.'),
  (2, 'direction', 'D', 'Engagement with the practical requirements of directing exercises is still developing. Advice to complete each exercise fully, one clear step at a time — stronger application and confidence are built gradually through repeated practice and engagement.'),
  (3, 'direction', 'A', 'Demonstrates a strong documentary vision with clear thematic focus. We encourage you to keep deepening observational nuance, by immersing youself in the story you will capture, letting smaller, unplanned moments enrich the theme. Keep it up.'),
  (3, 'direction', 'A', 'Handles real-life material with sensitivity and clarity. A strong instinct to now push toward more layered, interpretive readings of the subject. Keep up the good work.'),
  (3, 'direction', 'A', 'Structures the narrative effectively. We encourage you to refine pacing further so emotional beats land with even greater impact — a natural next step from an already solid foundation. Keep it up.'),
  (3, 'direction', 'A', 'Shows excellent control over subject engagement. Continue building on this by allowing more spontaneity to emerge, where real life can surprise the film. Keep up the good work.'),
  (3, 'direction', 'A', 'Integrates visuals and sound meaningfully. A strong base from which to explore more experimental storytelling approaches. Keep exploring and practicing.'),
  (3, 'direction', 'A', 'Maintains clear ethical awareness and responsibility toward the subject. We encourage you to keep questioning your own perspective critically, as this is what deepens documentary authorship.'),
  (3, 'direction', 'A', 'Leads collaboration effectively. Continue developing this by drawing stronger creative input from every department, raising the whole team''s contribution and teamwork. Well done.'),
  (3, 'direction', 'A', 'Demonstrates strong planning and execution. We encourage you to bring sharper focus in the edit, where tighter choices can further heighten narrative precision.'),
  (3, 'direction', 'B', 'Shows a clear understanding of documentary form. Advice to strengthen thematic depth by defining the film''s central idea early and ensuring every scene serves it — thematic richness develops through repeated research and reflection.'),
  (3, 'direction', 'B', 'Engages with subject matter effectively. Advice to develop more consistent narrative focus by identifying the one story you are telling and keeping each scene aligned to it — focus of this kind sharpens through repeated practice and feedback.'),
  (3, 'direction', 'B', 'Demonstrates a basic narrative structure. Advice to steady the pacing by mapping the film''s emotional progression in the edit, so momentum stays consistent — control of pacing comes through repeated practice and review.'),
  (3, 'direction', 'B', 'Shows awareness of real-world storytelling. Advice to enrich observational detail by spending longer with the subject and capturing specific, telling moments — observational depth grows through repeated, patient fieldwork.'),
  (3, 'direction', 'B', 'Integrates sound and visuals competently. Advice to develop richer layering by letting framing, movement, ambient sound, and silence work together — depth here comes through repeated practice and deliberate experimentation.'),
  (3, 'direction', 'B', 'Maintains a sound ethical consideration of the subject. To sharpen perspective, advice to commit to a clear point of view and support it with specific observed detail — clarity grows from the level of detail brought to each directorial choice.'),
  (3, 'direction', 'B', 'Collaborates well with the team. Advice to improve coordination between direction and other departments by holding clear briefings so everyone shares one vision — strong coordination develops through repeated practice and communication.'),
  (3, 'direction', 'B', 'Executes planning sufficiently. Advice to bring more sharpness and intent to editing choices by deciding what each cut should achieve for the story — decisive editing is a skill that strengthens through repeated practice and feedback.'),
  (3, 'direction', 'C', 'Shows partial understanding of Documentary storytelling, with thematic focus still unclear. Advice to identify the core idea of the film before scripting or shooting so every creative choice supports it — a clear theme is the spine that holds a documentary together.'),
  (3, 'direction', 'C', 'Engagement with the subject is currently inconsistent, which limits narrative depth. Advice to engage more deeply through stronger research, observation, and interview preparation — depth of understanding directly shapes the depth of the film.'),
  (3, 'direction', 'C', 'Structure is currently uneven, causing uneven progression. Advice to work on outlining scenes carefully to build a clear beginning, middle, and emotional progression — a skill that strengthens with deliberate practice.'),
  (3, 'direction', 'C', 'Currently relies on surface-level observation with limited interpretation. Advice to cultivate documentary structure, observation, and thematic development during research and pre-production — interpretive insight grows through this repeated, deliberate groundwork.'),
  (3, 'direction', 'C', 'Visual and sound elements are currently functional but not meaningfully integrated. Advice to explore how framing, movement, ambient sound, and silence can work together to strengthen mood and meaning — this integration develops through repeated, deliberate experimentation and is important for a filmmaker.'),
  (3, 'direction', 'C', 'Awareness of ethical considerations in representation is currently limited. Advice to be more mindful of perspective and representation when documenting real people and situations — ethical sensitivity is a core directorial responsibility that grows with reflective practice.'),
  (3, 'direction', 'C', 'Collaboration is currently inconsistent, which affects execution. Advice to improve communication with the crew members during planning and production so the final work feels more unified — strong collaborative habits are build through repeated practice, teamwork and feedback.'),
  (3, 'direction', 'C', 'Planning is evident but execution currently lacks clarity. Advice to develop more detailed shot breakdowns and production preparation to improve clarity during execution — the gap between plan and result closes through repeated, disciplined practice and reviews.'),
  (3, 'direction', 'D', 'A clear documentary vision is not yet established, with theme and direction still undefined. Advice to identify the core idea of the film before scripting or shooting so every creative choice supports it — finding the central idea is the essential first step toward a focused film.'),
  (3, 'direction', 'D', 'Engagement with the subject matter is currently weak, which weakens the narrative. Advice to engage more deeply through stronger research, observation, and interview preparation — a film can only go as deep as the director''s understanding of its subject.'),
  (3, 'direction', 'D', 'Structure is currently unclear, which affects comprehension. Advice to outline scenes carefully to create a clear beginning, middle, and emotional progression — structure is a foundational craft that builds step by step through repeated practice.'),
  (3, 'direction', 'D', 'Understanding of observational and non-fiction storytelling is still at an early stage. Advice to research documentary structure, observation, and thematic development during research and pre-production — these foundations grow steadily through repeated, supported practice.'),
  (3, 'direction', 'D', 'Visual and sound elements are not yet well integrated. Advice to explore how framing, movement, ambient sound, and silence can work together to strengthen mood and meaning — this craft develops only through repeated, deliberate practice and experimentation.'),
  (3, 'direction', 'D', 'Ethical considerations are currently overlooked. Advice to be more mindful of perspective and representation when documenting real people and situations — ethical awareness is a fundamental directorial responsibility that grows through guided, reflective practice.'),
  (3, 'direction', 'D', 'Collaboration is currently ineffective, leading to disjointed output. Advice to improve teamwork and communication with the crew during planning and production so the final work feels more unified. Collaboration as a skill is built through respectful communication, shared purpose and credits, trust and managing differences. Repeated collaborative practice and encouragement to crew goes a long way for a filmmaker.'),
  (3, 'direction', 'D', 'Planning and execution are currently weak across all production stages. Advice to actively develop detailed shot breakdowns and production preparation to improve clarity during execution — disciplined workflow is absolutely essential for a filmmaker and is built step by step through teamork and repeated practice.'),
  (4, 'direction', 'D', 'Understanding of workflow is currently limited and needs substantial development. Advice to develop more detailed shot breakdowns and production preparation to improve clarity during execution — a reliable workflow grows gradually through repeated practice and guidance.'),
  (5, 'direction', 'A', 'Balances narrative clarity and audience engagement effectively. Advice to keep strengthening visual storytelling over dialogue, letting images carry even more of the meaning. Keep up the good efforts.'),
  (5, 'direction', 'A', 'Demonstrates strong planning and execution. Well done. Advice to refine episodic cliffhangers further, as sharper hooks can elevate the impact across an entire series.'),
  (5, 'direction', 'B', 'Shows a clear understanding of episodic direction. Advice to strengthen thematic consistency across episodes by defining the series'' central theme and threading it through each one — consistency of this kind develops through careful planning and repeated practice. Keep up the good work.'),
  (5, 'direction', 'B', 'Attempts multi-episode storytelling effectively. Advice to give character arcs stronger continuity by mapping each character''s journey across the full series before shooting — sustained arcs are built through deliberate planning and repeated practice.'),
  (5, 'direction', 'B', 'Demonstrates awareness of the VOD format. Advice to improve audience engagement by studying how hooks, episode length, and pacing hold viewers on these platforms — format-specific instincts develop through research and repeated practice.'),
  (5, 'direction', 'B', 'Maintains basic directorial control. Advice to even out tonal shifts between episodes by defining the series'' tone clearly and checking each episode against it — consistent tone is built through deliberate planning and feedback.'),
  (5, 'direction', 'B', 'Coordinates departments adequately. Advice to strengthen integration with narrative intent by briefing each department on the story''s goals, not just their tasks — unified output develops through repeated, clear communication and collaborative efforts.'),
  (5, 'direction', 'B', 'Uses visual storytelling in parts but still leans heavily on dialogue. Advice to practice carrying key beats through composition, movement, expressions and environment instead of just words — a visual vocabulary strengthens through repeated practice and feedback.'),
  (5, 'direction', 'B', 'Follows structured planning. Advice to bring more polish to execution across all episodes by reviewing each one against the plan and refining weak spots — consistent polish comes through repeated practice and feedback.'),
  (5, 'direction', 'B', 'Develops narrative progression well. Advice to strengthen episode endings by designing a clear dramatic hook for each one that pulls viewers into the next — strong cliffhangers are crafted through deliberate practice and review.'),
  (5, 'direction', 'C', 'Understanding of episodic storytelling is currently limited, with weak thematic coherence. Advice to identify a clear central theme before scripting — when a theme threads consistently across episodes, the series gains identity and purpose.'),
  (5, 'direction', 'C', 'Series structure is attempted but episodes currently feel disconnected in tone and narrative. Advice to establish a series bible defining tone, world, and narrative arc so all episodes feel part of the same story universe — this discipline strengthens with practice.'),
  (5, 'direction', 'C', 'Character development is currently inconsistent, which affects engagement. Advice to map each character''s arc clearly before production — audiences invest in characters who change and grow in ways that feel earned.'),
  (5, 'direction', 'C', 'Direction skills are present but control over pacing and progression is still developing. Advice to analyse how rhythm and momentum are shaped in the edit and on set — pacing is a craft skill that improves significantly with deliberate practice. A tight edit can engage the audiance far better than a loose and slow pace.'),
  (5, 'direction', 'C', 'Awareness of the VOD format and retention strategies is currently limited. Advice to research how VOD audiences engage with series content — understanding hooks, episode length, and retention techniques is essential for this format. Please enagage in practice.'),
  (5, 'direction', 'C', 'Communication with departments is currently inconsistent, which affects narrative quality. Advice to hold structured, regular briefings with every department so the story stays unified — strong coordination and collaboration builds through repeated practice along with clear communication.'),
  (5, 'direction', 'C', 'Currently relies primarily on dialogue, with minimal visual storytelling. Advice to develop a visual storytelling vocabulary in which composition, movement, and environment carry narrative weight alongside, rather than instead of, words — this grows through repeated practice.'),
  (5, 'direction', 'C', 'Pre-production planning is currently underused. Advice to explore it more actively through detailed shot lists, rehearsals, and group briefings. Communication and preparation is what turns good intentions into polished execution, which strengthens with teamwork and practice.'),
  (5, 'direction', 'D', 'A clear episodic vision is not yet established, with no consistent theme or identity. Advice to establish what the series is about and how each episode serves that core — defining this is the essential first step toward a coherent series.'),
  (5, 'direction', 'D', 'Episodes are currently disjointed, lacking continuity or progression. Advice to plan continuity and narrative progression across episodes at the series-design stage so each episode connects and builds on the one before — this structural craft develops through repeated practice.'),
  (5, 'direction', 'D', 'Character arcs are currently unclear or absent, which reduces audience engagement. Advice to define character arcs before scripting — change, conflict, and growth are what make audiences return to a series, and arc-building strengthens with deliberate practice.'),
  (5, 'direction', 'D', 'Control over tone, pacing, and storytelling is currently minimal. Advice to develop command over each through focused study and consistent, reflective practice — these core skills are built gradually, one deliberate step at a time.'),
  (5, 'direction', 'D', 'Integration of departments is currently weak, leading to inconsistent output. Advice to strengthen teamwork with interdepartmental coordination through clear, regular communication so the overall output feels cohesive — unified collaboration is built through repeated practice and feedback.'),
  (5, 'direction', 'D', 'Currently over-relies on dialogue with little cinematic expression. Advice to focus on visual storytelling, communicating emotion through action and imagery — a cinematic vocabulary develops gradually through discussions with Cinematography department, and repeated collaborative practice.'),
  (5, 'direction', 'D', 'Planning and execution are currently weak across production stages. Advice to treat each production stage as a discipline in itself — systematic planning, clear communication on responsibilities, along with structured execution are professional skills built through persistent practice.'),
  (5, 'direction', 'D', 'Understanding of VOD storytelling and collaborative workflow is currently limited. Advice to analyse VOD series structure and platform conventions while developing stronger collaborative practices — both are foundational competencies that grow through teamwork and repeated, supported practice.'),
  (6, 'direction', 'D', 'Planning and workflow execution are currently weak across production stages. Advice to develop structured habits for each phase — planning, execution and review — as discipline at every stage is what turns intent into outcome, built gradually through teamwork and practice.'),
  (6, 'direction', 'D', 'Currently struggles to meet duration and deliverable standards. Advice to sereriously attempt to imporve, treat meeting deliverable requirements as a professional baseline and to seek support early if challenges arise. Reliable delivery is a habit built step by step with guidance and practice.'),
  (1, 'production', 'A', 'Displays masterful technical command, with every production element polished to a professional finish — the next step is to build teamwork and morale of the team. Well done.'),
  (1, 'production', 'A', 'Demonstrates a sophisticated grasp of the brief, translating complex ideas into clear outcomes with precision; tightening the final alignment between concept and result during practice will take this even further. Well done.'),
  (1, 'production', 'A', 'Every production choice is backed by strong intent, showing a purposeful link between concept and final result — a real strength to keep building on. Keep it up.'),
  (1, 'production', 'A', 'High-level execution runs throughout the project, finished to a superior standard with meticulous attention to detail — excellent, professional-grade work. Well done.'),
  (1, 'production', 'A', 'Successfully bridges creative experimentation with disciplined production; sharpening the alignment between idea and outcome is the next level to aim for. Keep it up.'),
  (1, 'production', 'A', 'Maintains strong control across every phase of the project, delivering a cohesive and unified final production — a clear, dependable strength. Well done.'),
  (1, 'production', 'A', 'Exhibits decisive, intelligent control over the medium, consistently choosing solutions that sharpen clarity — keep developing this instinct toward ever-bolder choices.'),
  (1, 'production', 'A', 'Demonstrates a powerful sense of resolve; the work is not only well-produced but carries genuine craftsmanship — a strong foundation to build a personal voice on. Keep it up.'),
  (1, 'production', 'B', 'Demonstrates a solid grasp of technical skills. Advice to iron out the minor inconsistencies in the final project by building a pre-delivery checklist and reviewing each pass against it — consistency comes through repeated practice and feedback.'),
  (1, 'production', 'B', 'Shows a clear understanding of the project goals. To tighten the link between concept and outcome, note the intended purpose beside each production choice and check the result against it — this alignment strengthens with repeated practice and feedback.'),
  (1, 'production', 'B', 'Execution is generally strong. Advice to develop more rigorous quality control by reviewing the work in dedicated detail-checking passes before finalizing — this polish comes through repeated practice and feedback.'),
  (1, 'production', 'B', 'Outcomes form a functional bridge between theory and practice. To align them more fully with the brief, revisit each requirement during production and confirm the work meets it — tighter alignment develops through repeated practice and feedback.'),
